con:mockOperation.con:dispatchPath:
import com.eviware.soapui.support.XmlHolder
import com.eviware.soapui.impl.wsdl.support.wsdl.WsdlContext
import com.eviware.soapui.impl.wsdl.support.wsdl.WsdlValidator
import com.eviware.soapui.impl.wsdl.panels.mockoperation.WsdlMockRequestMessageExchange

synchronized(mockRequest.context.mockService){

mh = new se.skl.rivta.tksupport.soapui.MockHelper(mockRequest, mockOperation)
context.validationMessages = mh.getSchemaErrorsInRequest() ?: mh.getSchematronErrorsInRequest("constraints.xml") ?: mh.getEmptyElementsInRequest() ?: null
if (context.validationMessages) {
	return "SoapFault"
}

def holder = new XmlHolder( mockRequest.requestContent )
holder.namespaces['soapenv'] = 'http://schemas.xmlsoap.org/soap/envelope/'
holder.namespaces['urn'] = 'urn:riv:itintegration:registry:1'
holder.namespaces['urn1'] = 'urn:riv:clinicalprocess:healthcond:actoutcome:GetLaboratoryOrderOutcomeResponder:4'
holder.namespaces['urn2'] = 'urn:riv:clinicalprocess:healthcond:actoutcome:4'

def patientId = holder.getNodeValue('/soapenv:Envelope/soapenv:Body/urn1:GetLaboratoryOrderOutcome/urn1:patientId/urn2:extension')
def patientIdType = holder.getNodeValue('/soapenv:Envelope/soapenv:Body/urn1:GetLaboratoryOrderOutcome/urn1:patientId/urn2:root')
def careGiverHSAId = holder.getNodeValue('/soapenv:Envelope/soapenv:Body/urn1:GetLaboratoryOrderOutcome/urn1:careGiverHSAId/urn2:extension')
def careUnitHSAId = holder.getNodeValue('/soapenv:Envelope/soapenv:Body/urn1:GetLaboratoryOrderOutcome/urn1:careUnitHSAId/urn2:extension')
def careContactId = holder.getNodeValue('/soapenv:Envelope/soapenv:Body/urn1:GetLaboratoryOrderOutcome/urn1:patientId/urn2:extension')
def sourceSystemHSAId = holder.getNodeValue('/soapenv:Envelope/soapenv:Body/urn1:GetLaboratoryOrderOutcome/urn1:sourceSystemHSAId/urn2:extension')

context.patientId = patientId
context.patientIdType = patientIdType
context.careGiverHSAId = careGiverHSAId ?: "careGiverHSAId"
context.careUnitHSAId = careUnitHSAId ?: "careUnitHSAId"
context.careContactId = careContactId ?: "careContactId"
context.sourceSystemHSAId = sourceSystemHSAId ?: "sourceSystemHSAId"

if (mockRequest.requestHeaders['x-mock-response'] != null){
	return mockRequest.requestHeaders['x-mock-response'][0]
}
return"Compliant Content Response" 
}
